1	import { readFileSync } from "node:fs";
2	import { quote, claim, type Item, type Incident } from "./claim-office.js";
3	
4	const INSURANCE_VALUES: Record<string, number> = {
5	  sword: 1000,
6	  amulet: 600,
7	  staff: 800,
8	  potion: 400,
9	  rune: 250,
10	  moonstone: 250,
11	};
12	
13	const { customer, steps } = JSON.parse(readFileSync(0, "utf-8"));
14	
15	type Step =
16	  | { op: "quote"; items: Item[] }
17	  | { op: "claim"; policy: number; incident: Incident };
18	
19	const quotePolicies: Item[][] = [];
20	const remainingCaps = new Map<number, number>();
21	
22	function initialCap(items: Item[]): number {
23	  return items.reduce((sum, item) => sum + 2 * INSURANCE_VALUES[item.type], 0);
24	}
25	
26	function remainingCapFor(policyIndex: number): number {
27	  const existing = remainingCaps.get(policyIndex);
28	  if (existing !== undefined) return existing;
29	  const cap = initialCap(quotePolicies[policyIndex]);
30	  remainingCaps.set(policyIndex, cap);
31	  return cap;
32	}
33	
34	const results = (steps as Step[]).map((step) => {
35	  if (step.op === "quote") {
36	    quotePolicies.push(step.items);
37	    return { premium: quote(customer, step.items) };
38	  }
39	  const policyItems = quotePolicies[step.policy];
40	  const result = claim({ items: policyItems }, step.incident, remainingCapFor(step.policy));
41	  remainingCaps.set(step.policy, result.remainingCap);
42	  return result;
43	});
44	process.stdout.write(JSON.stringify({ results }));
